		if (reversed == null) { reversed = false; }
		var props = new Object();
		props.mode = mode;
		props.startPosition = startPosition;
		props.labels = { "Start": 0, "Finished": 16 };
		props.loop = loop;
		props.reversed = reversed;
		cjs.MovieClip.apply(this, [props]);

		// timeline functions:
		this.frame_0 = function () {
			this.stop();
		}
		this.frame_15 = function () {
			this.stop();
			this.parent.parent.parent.LmsUpdateUpLevel(3);//UpLevel ilerlemesini db ye kayıt ediyoruz.
			this.parent.parent.parent.CompletedPercentTask(3);//Adanın üstündeki yüzde bar'ın ilerlemesini sağlıyoruz.
			if (this.parent.parent.parent.getDoItTask(3) == true) {
				var mc = this.parent.Task_4;
				mc.BookMarkBtn.visible = true;
				mc.BookMarkBtn.play();
				var TaskDescriptionArry = this.parent.parent.parent.getIslandTaskDescriptionArry();

				this.parent.parent.TaskInformation.ParsomenAlt.TaskInformation_Txt.text = TaskDescriptionArry[3][3];// birinci adadki ikinci görev
				this.parent.parent.TaskInformation.gotoAndPlay(1);//Ada görevi yazan parşomen açılıyor.

			} else {
				this.parent.parent.TaskInformation.ParsomenAlt.TaskInformation_Txt.text = this.parent.parent.parent.NoTaskInformation;//"Henüz göreviniz bulunmamaktadır.";// birinci adadki ikinci görev
				this.parent.parent.TaskInformation.gotoAndPlay(1);//Ada görevi yazan parşomen açılıyor.	
			}
			this.TlMc.gotoAndPlay(1);
		}
		this.frame_16 = function () {
			this.stop();
		}

		// actions tween:
		this.timeline.addTween(cjs.Tween.get(this).call(this.frame_0).wait(15).call(this.frame_15).wait(1).call(this.frame_16).wait(5));

		// ParaEfekti
		this.TlMc = new lib.TlEffects();
		this.TlMc.name = "TlMc";
		this.TlMc.setTransform(0.5, 0, 0.5627, 0.5533);
		this.TlMc._off = true;

		this.timeline.addTween(cjs.Tween.get(this.TlMc).wait(15).to({ _off: false }, 0).to({ _off: true }, 1).wait(5));

		// bookmark
		this.BookMarkBtn = new lib.BookMark();
		this.BookMarkBtn.name = "BookMarkBtn";
		this.BookMarkBtn.setTransform(23.15, -44.1, 0.8789, 0.8776, 0, 0, 0, 0, -0.1);

		this.timeline.addTween(cjs.Tween.get(this.BookMarkBtn).to({ _off: true }, 1).wait(20));

