			function updateLevelControl(totalPoint, upLevel) {
				let ArrayLevelControl = new Array(5).fill(null).map(() => new Array(6).fill(false));

				for (let i = 0; i < upLevel; i++) {
					let currentIsland = Math.floor(i / 6);
					let currentTask = i % 6;

					if (currentIsland < ArrayLevelControl.length) {
						ArrayLevelControl[currentIsland][currentTask] = true;
					}
				}

				return ArrayLevelControl;
			}
			// _root.levelArray diziindeki gönderilen true sayılarnı sayar bunu  ada alt görevlerinin yapılıp yapılmadığı sayısını bulup doTast değişkenine ataycağız.
			function trueCountInRow(array, rowIndex) {
				// Belirtilen satırdaki 'true' değerlerinin sayısını bul
				// rowIndex ile hangi satırın inceleneceği belirlenir
				if (array[rowIndex]) {
					const count = array[rowIndex].filter(value => value === true).length;
					return count;
				} else {
					// Eğer belirtilen rowIndex, dizinin sınırları dışındaysa
					return 'Belirtilen satır dizide bulunmuyor.';
				}
			}


