			// Gelen datalar işleniyor. İlk başlangıç
			function startGame() {

				//ilk üçü yazdıran fonksiyonu tetikliyoruz.	
				LeaderOrderFnc();

				Object.entries(GamerInformation).forEach(p => {

					if (p[1].Login == 1) {
						// ilerlemeler uplevel üzerinden olacak skor tablolarına upleveller yazılacak. 
						//var TotalSale 	= p[1].Sales.TotalSale;
						//var TotalPoint = p[1].UpLevel > 30 ? 30 : p[1].UpLevel; //!!! burası çpok önemli kafa karıştırmasın burada gelen puanlar yerine gelen uplevel üzerinden ilerleme yapıyuoruz.

						var Gender = p[1].Gender; //2 kadın 1 Erkek
						var Image = p[1].Image;
						var Name = p[1].Name;
						var Date = p[1].Date;
						var Language = p[1].Language;
						var BadgeNumber = p[1].BadgeNumber;
						var BadgeName = p[1].BadgeName;

						_root.TotalPoint = p[1].TotalPoint > 30 ? 30 : p[1].TotalPoint;// Kullanıcının  lms'de yaptığı görev sayısı.
						_root.UpLevel = p[1].UpLevel > 30 ? 30 : p[1].UpLevel;//Kulanıncının oyunda yapacağı görev sayısı. 				

						UserImage = Image; // Resim yolunu global değişkene atıyoruz.

						_root.levelArry = updateLevelControl(_root.TotalPoint, _root.UpLevel);// gelen ada ilelmesini glbal diziye aktarıyoruz.
						console.log(_root.levelArry);
						globalBadgeNumber = BadgeNumber;
						//globalBadgeName=BadgeName.split(":");	

						//IsChar değişkenini Gelen Gender değeri 0 ise boy 1 işse gitl yapıyoruz.
						IsChar = Gender == 1 ? "boy" : "girl";

						if (Gender == 1) {
							IsChar = "boy";
						} else if (Gender == 2) {
							IsChar = "girl";
						} else if (Gender == 0) {
							IsChar = "boy";
						};

						var ProfilImage = Image;
						var ImageHolderMc = _root.TopMenu.DateContainer.ProfilMc;
						ImageLoad(ProfilImage, ImageHolderMc);

						// Rozet sayısını yazdırıyoruz.
						_root.TopMenu.BadgePointMc.IslandTotal_txt.text = BadgeNumber;

						// gelen dile göre oyunun çevirisini yapıyoruz.
						if (Language == 2) {

							IslandTaskDescriptionArry = IslandTaskDescriptionArry; //Görev açıklamları ingilizce çeviriliyor
							_root.FinishedGameMc.FinishedTxt.text = FinishedTxt; //Bitiş tebrik yazısı ingilizce yapılıyor.
							_root.BottomMenuMc.Btn_0.TitleMc.PointTableTr.visible = false;
							_root.BottomMenuMc.Btn_0.TitleMc.PointTableENg.visible = true; // puan tablosu yazısını ingilizce yaptık.										
							_root.BottomMenuMc.Btn_2.QuitTr.visible = false;
							_root.BottomMenuMc.Btn_2.QuitEng.visible = true;
							CompletedTaskTr = CompletedTaskEng;
							_root.FinishedGameMc.FinishedTxt.text = FinishedTxtEng;
							_root.FinishedGameMc.TamamBtn.TamamBtnTR.visible = false;
							_root.FinishedGameMc.TamamBtn.TamamBtneNG.visible = true;
							_root.GameTitle.GamTitleTr.visible = false;
							_root.GameTitle.GamTitleEng.visible = true;

						}

						//!!!  Çok önemli burada level ve sublevelları hesaplıyoruz.
						//console.log("Total puan: " + TotalPoint  + " / " + TotalIsLandSales);									
						IslandLevel = Math.floor(_root.UpLevel / TotalIsLandSales);
						//alert("2. ada leveli ilk hessap : " +  IslandLevel);
						// eğer satış 450'yi geçtiyse Ada levelını 5 den 4 çekiyoruz. Çünkü ada mcler 4 bitiyor.
						//console.log(IslandLevel);
						if (IslandLevel >= 5) {
							IslandLevel = 4;
						};

						//console.log("Level:" + IslandLevel);
						var IslandOfSales = (_root.UpLevel % TotalIsLandSales) == 0 ? TotalIsLandSales : (_root.UpLevel % TotalIsLandSales); // Aylık gelen satışın 90 modunu alıp ada başı satış miktarını buluyoruz.
						//console.log("sublevel hesap: " + IslandOfSales + " -- " + TotalTaskSales);
						IslandSubLevel = Math.floor(IslandOfSales / TotalTaskSales);
						// buluduğu adaya yeni başlamışsa 90 veya katlarıysa sub levelı 0'a çekiyoruz.
						if (IslandLevel == Math.floor(_root.UpLevel / IslandOfSales)) {

							IslandSubLevel = 0;
						}
						// Güncel satış bilgilerinive ada bilgisini global değişlkenlere ataıyoruz.

						MemmoryMonthSale = _root.UpLevel;
						MemoryLevel = IslandLevel

						//console.log("SubLevel:" + IslandSubLevel);			
						var GamerProfile = _root["GamerProfile_" + (IslandLevel)];
						// Badge 0 dan büyükse karakterler üstündeki rozetleri gösteriyoruz.
						if (BadgeNumber > 0) {
							GamerProfile.GenderMc.CharBadge.visible = true;
						}
						_root.TopMenu.hedef_mc.IslandTotal_txt.text = _root.UpLevel + " / " + TotalGameSales;

						//Satışları txt'kere yazdırıyoruz.		

						//----------------------------------------------------------------------

						GameProfilLevel = IslandLevel; // çizgi gelince açılacak olan profili burada belirliyoruz.
						_root.TopMenu.TitleContainer.titleTxtMc.gotoAndStop(IslandLevel);

						// Title Ada isminin altına adadaki tamaladıpı görevler kadar yıldız koyuyoruz.		
						SubLevelStartsCreate(IslandSubLevel);
						//Güncelleme tarihini yazdırıyoruz.
						DateTimeOf(Date, Name);
						//Küçük adaların görevlerinin açılmasını sağlıyoruz.

						// Adaların üstüne basılma olayı			 

						//newtext(_root["GamerProfile_" + (IslandLevel)].NameMc, Name, 8, 2, "#ffffff", "7px Tahoma");
						_root["GamerProfile_" + (IslandLevel)].Name_Txt.text = Name;

						var TotalLoadingPercent = Math.floor(100 * _root.UpLevel) / TotalGameSales; //Oyundaki genel loading bar ilerlemesi hesaplamasını yapıyoruz.
						_root.TopMenu.TopMenuBar.Loading.ProgressBar.GreenBar.gotoAndStop(TotalLoadingPercent - 1); //Framler 0 dan başladığı için -1 yaptık.
						//!!! önemli

						smallIslanBtn(IslandLevel); // gelen level kadar adaların basılma olayını tanımlıyoruz ona göre büyük adalar açılacak.

						console.log("Oyun bittimi ki :" + _root.UpLevel + " >= " + TotalGameSales)
						if (_root.UpLevel >= TotalGameSales) {
							LeaderOrderFnc(); // ilk 3 kişiyi sıralıyoruz.								
							_root.GameFinishScreen();
						} else {
							//Eğer toplam satış yapılmamışsa güncelleme devam ediyor.
							//setInterval( RefresGameFnc,RefreshTime );
						}

					};

				});

				_root.ISlandGuide.gotoAndPlay(1);
			};

			// ufak adaların level seviylerine göre basılmasını ayarlıyoruz örnek level 0 sa  ilk adanın basılma oalyını yapıyoruz.
			function smallIslanBtn(IslandLevel) {
				//alert(" Küçük adalar level: " + IslandLevel + " alt level: " +IslandSubLevel );
				if (_root.TotalPoint >= 0) {
					for (var j = 0; j < IslandLevel + 1; j++) {

						// Adaların basılmasını yapıyoruz.
						var CurrentIslandNo = (j); // Buradaki j+1	basılan adanın numarası her level ada numarasına karşılık gelir	
						//alert("Island_" + j);
						_root["Island_" + j].btn.addEventListener("click", BigBtnFnc.bind(this, CurrentIslandNo));
						//Hangi nolu adalrın bulutları açık dizimize kayıt ettiriyoruz.

						CloudOpenControlArry[j] = true;
						//Alt ada seviyelerine iniyoruz.								
						for (var i = 0; i < 6; i++) {

							if (i < IslandSubLevel) {

								var GamerProfileStarMc = _root["GamerProfile_" + (j)]["star_" + (i + 1)];
								GamerProfileStarMc.alpha = 1;

							} else {

							};
						};

					}
				}
			};



			// Görevler tamamlandıkça  ana sayfadaki puan tablosunu ve yüzde barını güncelliyoru<.
			this.refreshMainPointPercent = function () {

			}

			//!!! Büyük adaların açıldığı fonksiyon çok çönemli buradan görev tamamlama yapıyoruz.		
			function BigBtnFnc(CurrentIslandNo) {

				//alert("büyük ada no: " + CurrentIslandNo);

				_root.BigIslandContainer.AllTasked.visible = false;

				//Büyük adanın level bilgilerni tanımlıyoruz.	
				var IslandSubLevel = 0; // uplevela göre alt görevler
				IslandSubLevelTotalPoint = 0; // total levellara göre alt görevler	
				var TotalPoint = _root.TotalPoint; // lms de yapılan görev start fonsiyonun içinden yüklenir
				var UpLevel = _root.UpLevel; //Up level kullanıncın oyunda tamamladığı görevler adanın içindeki butonlara basılınca artar
				var IslandLevel = Math.floor(UpLevel / _root.TotalTaskSublevel); // up levela göre hesaplanır kullanıcın kacıncı adada olduğunu gösterir.
				var TotalPointLevel = Math.floor(TotalPoint / _root.TotalTaskSublevel);// total pointe göre level hesaplıyoruz.
				MemorySublevel = 0;
				// Eğer açıulan  ada mevcut leveldan küçükse ada yüzdesini 100 yapıyoruz.


				IslandSubLevel = (UpLevel % _root.TotalTaskSublevel);//Uplevella göreyapılan alt görev sayısı	
				IslandSubLevelTotalPoint = (TotalPoint % _root.TotalTaskSublevel);

				// eğer uplevel 30 olduysa level 5 olur o yüzden 4' cekiyoruz.'
				if (IslandLevel == 5) {
					IslandLevel = 4;
				};

				//Burası çok önemlli, oyun levellarına göre ada alt görev sayılarını  ayarlıyoruz
				// geleen görev sayısı 6 dan küçükse 

				if (TotalPoint > _root.TotalTaskSublevel) {
					// eğer gelen göreve göre level sayısı uplevele göre  level sayısından  büyükse alt görev sayısını 5 yapıyoruz.
					//alert("totalpoint level: " + TotalPointLevel + " > ıslandLevel " + IslandLevel);		
					if (TotalPointLevel > IslandLevel) {
						IslandSubLevelTotalPoint = 5;
						//alert("test: " + IslandSubLevelTotalPoint);

					}
				}

				if (TotalPoint == 6) {

					IslandSubLevelTotalPoint = 5;

				} else if (TotalPoint == 12) {
					IslandSubLevelTotalPoint = 5;
				} else if (TotalPoint == 18) {
					IslandSubLevelTotalPoint = 5;
				} else if (TotalPoint == 24) {
					IslandSubLevelTotalPoint = 5;
				} else if (TotalPoint == 30) {
					IslandSubLevelTotalPoint = 5;
				}

				console.log("b--> IslandSublevel: " + IslandSubLevel);
				doItTask = (IslandSubLevelTotalPoint + 1) - IslandSubLevel;



				// eğer uplevel ile total point yani lms den gelen görec sayısı ile yapılana görev sayısı eşitse  doITask=0 lıyoruz.		

				if (TotalPoint == UpLevel) {
					doItTask = 0;
				}

				// uplevel dan totallevel çıkartıyoruz.yapılacak görev sayısı	

				//Adalardaki yüzde artışını görev tamamladıkça yapan fonksiyonu çalıştırıyoruz.

				_root.CompletedPercentTask(IslandSubLevel);
				_root.BigIslandContainer.gotoAndStop(CurrentIslandNo); //!!! Açılan büyük adanın frame'ine gidiyoruz. Hangi büyük adanın açılacağını belirliyoruz.

				CampionListKey(false) // ilk 3 sıralama listeyi kapatıyoruz.						
				_root.TopMenu.TitleContainer.titleTxtMc.gotoAndStop(CurrentIslandNo);
				_root.TopMenu.TitleContainer.StarsContainer.gotoAndStop(IslandSubLevel);

				//var IslandOfSales = (UpLevel % TotalIsLandSales) == 0 ? TotalIsLandSales : (UpLevel % TotalIsLandSales); // Aylık gelen satışın 90 modunu alıp ada başı satış miktarını buluyoruz.
				//var TaskFrameNo = (IslandOfSales % (TotalTaskSales + 1)) == 0 ? 0 : (IslandOfSales % (TotalTaskSales + 1)); // Adanın tamamlann toplam görev sayısını 15 mod alarak hangi görevde hangi aşamada öğreniyoruz.		

				_root.BigIslandContainer.visible = true;
				_root.alphaMc.visible = true;
				_root.TopMenu.TopMenuBar.visible = false;
				_root.BottomMenuMc.visible = false;
				_root.SoundBtn.visible = false;// büyük ada açıldığınnda alt menü butonları ve  ses butonunu görünmez yapıyoruz.		
				alphaEffect(_root.alphaMc, .8);//Büyük ada arka plan mavilik alphasını .9 yapıyoruz.
				setTimeout(alphaEffect, 500, _root.BigIslandContainer, 1); //Büyük adaların bulunduğu containerın alphasını 1 yapıyoruz.		

				//Buradaki TotalTaskSublevel 6 tane burada up level kadar ileleme yapıyoruz. Totalpoint ile up level aarsındakilerle baıslma sağlıyoruz.

				//Kullanıcı ada görevlerini kendi geçecek şekilde tamamlıyoruz.
				var TaskContent = "";
				// ilk olarak büyük adadaki parşomene yapılacak görev yok yazıyoruz.
				_root.BigIslandContainer.TaskInformation.ParsomenAlt.TaskInformation_Txt.text = _root.NoTaskInformation;
				for (var i = 0; i < _root.TotalTaskSublevel; i++) {
					//alert("döngüdeki level: " + IslandLevel + " -- Task_"+ i);
					var IslandTaskMc = _root.BigIslandContainer["Island_" + IslandLevel]["Task_" + (i + 1)]; // Adadaki görev movieclipleri

					IslandTaskMc.gotoAndStop("Start"); // Tüm adadaki görevleri ilk frame çekiyoruz.
					_root.BigIslandContainer.TaskInformation.gotoAndPlay(1); // Ada görevi yazan parşomen açılıyor.


					IslandTaskMc.BookMarkBtn.index = i;
					IslandTaskMc.BookMarkBtn.cursor = "pointer";
					IslandTaskMc.BookMarkBtn.addEventListener("click", function (evt) {
						BookMarkBtnEvent(evt);
					});

					IslandTaskMc.BookMarkBtn.visible = false;

					// Uplevela göre sublevel hesaplayıp adada ilerlemeyi sağlıyoruz.

					if (i < IslandSubLevel) {

						IslandTaskMc.gotoAndStop("Finished");//		
					}

					// Adadaki yapılacak görevde duruyoruz.

					if (doItTask > 0) {
						if (i == IslandSubLevel) {
							_root.BigIslandContainer.TaskInformation.visible = true;
							_root.BigIslandContainer.AllTasked.visible = false;

							var IslandLoadingPercent = Math.abs((Math.floor((100 * IslandSubLevel) / _root.TotalTaskSublevel))); // Yüzde olarak hesapladık loadingBar frame'ine yönlendireceğiz.
							_root.BigIslandContainer.IslandLoading.gotoAndStop(IslandLoadingPercent - 1); // adalardaki görevleri tamamlama yüzdelerini gçsteriyoruz. Framler sıfırdan başladığı için -1 yaptık
							TaskContent = IslandTaskDescriptionArry[CurrentIslandNo][IslandSubLevel];
							_root.BigIslandContainer.TaskInformation.ParsomenAlt.TaskInformation_Txt.text = TaskContent;
							IslandTaskMc.BookMarkBtn.visible = true;
							IslandTaskMc.BookMarkBtn.gotoAndPlay(2);

						}

					} else {
						_root.BigIslandContainer.TaskInformation.visible = true;
						_root.BigIslandContainer.TaskInformation.ParsomenAlt.TaskInformation_Txt.text = _root.NoTaskInformation;

					}
				}

				if ((CurrentIslandNo < IslandLevel)) {
					CompletedBigIsland(CurrentIslandNo);
				}


				// eğer oyun bitmişse son adaki görevleride kapatıyoruz.
				if (_root.UpLevel >= 30) {

					CompletedBigIsland(CurrentIslandNo);
					_root.TopMenu.TitleContainer.StarsContainer.gotoAndStop(6);
				}

				// Buyük adalardaki karakterleri gelen gender değerine göre ayarlıyoruz.			

				_root.BigIslandContainer["Island_" + (IslandLevel)].CharsAnime.visible = true;


			};

			// adalardaki tüm görevler tamamlandıysa büyük adadaki yüzde barı fulleyip tüm görev listesini çıkartıyoruz.

			function CompletedBigIsland(CurrentIslandNo) {

				//alert("Bu adaki tüm görevler tamamlnamıştır. ada no" +  CurrentIslandNo);

				_root.BigIslandContainer.gotoAndStop(CurrentIslandNo);
				_root.BigIslandContainer.TaskInformation.visible = false;

				_root.BigIslandContainer.AllTasked.visible = true;

				_root.BigIslandContainer.AllTasked.ParsomenAlt.TaskInformation_Txt.text = "Tamamlanan Görevler\n1. " + IslandTaskDescriptionArry[CurrentIslandNo][0] + "\n" + "2. " + IslandTaskDescriptionArry[CurrentIslandNo][1] + "\n" + "3. " + IslandTaskDescriptionArry[CurrentIslandNo][2] + "\n" + "4. " + IslandTaskDescriptionArry[CurrentIslandNo][3] + "\n" + "5. " + IslandTaskDescriptionArry[CurrentIslandNo][4] + "\n" + "6. " + IslandTaskDescriptionArry[CurrentIslandNo][5];
				_root.TopMenu.TitleContainer.StarsContainer.gotoAndStop(6);	// tamamlana adanın yıldılarını full açıyoruz.	
				_root.BigIslandContainer.AllTasked.gotoAndPlay(1);

				_root.BigIslandContainer.IslandLoading.gotoAndPlay(1); // yüzde barı 100 yapıyoruz.	

				for (i = 0; i < 6; i++) {
					//console.log("Island_: " + j + " Task_: " + i );
					_root.BigIslandContainer.gotoAndStop(CurrentIslandNo);
					var IslandTaskMc = _root.BigIslandContainer["Island_" + (CurrentIslandNo)]["Task_" + (i + 1)];
					IslandTaskMc.gotoAndStop("Finished");// küçük adalar tüm görevleri son frame getiriyoruz.
				}
			}




