				var index = mc.index;
				mc.visible = false;//Görevlerdeki book,Mark butonularını göreünmez yapıyoruz.

				var levelNo = Math.floor(_root.UpLevel / 6);
				var IslandTaskMc = _root.BigIslandContainer["Island_" + levelNo]["Task_" + (index + 1)]; // Adadaki görev movieclipleri	

				//alert("IslandLevel: " + levelNo + " index:" +index + " ada name :" + _root.BigIslandContainer["Island_" + levelNo].name);			
				_root.BigIslandContainer["Island_" + levelNo].CharsAnime.gotoAndPlay("task_" + (index + 1));


