			function newtext(obje, TextToDisplay, xposition, yposition, textcolor, textfont) {
				var textvar = new createjs.Text();
				textvar.x = xposition;
				textvar.y = yposition;
				textvar.color = textcolor;
				textvar.font = textfont;
				textvar.text = TextToDisplay;
				obje.addChild(textvar);
			};


			function alphaEffect(mc, distance) {
				//mc.alpha = 0;

				createjs.Tween.get(mc)
					.to({
						alpha: distance
					}, 300, createjs.Ease.linear)
					.call(alphaEffectComplete);
			}

			function alphaEffectComplete() {
				// aplha effect bitti
				//console.log("bitti");

			}

			function ScaleEffect(mc, xScale, yScale, delayTime) {

				createjs.Tween.get(mc)
					.to({
						scaleX: xScale,
						scaleY: yScale,
					}, delayTime, createjs.Ease.elasticOut)
					.call(ScaleEffectCompleted);
			}

			function ScaleEffectCompleted() {


			}

			// resimleri çekecek olan fonksiyonumuzu tanımlıyoruz.

			function ImageLoad(url, mc) {
				var img = new Image();
				img.src = url;
				img.onload = function () {
					// Maksimum genişlik ve yüksekliği belirle
					var maxWidth = 80;
					var maxHeight = 80;

					// Resmin oranını koruyarak genişlik ve yüksekliği sınırla
					var scale = Math.min(maxWidth / img.width, maxHeight / img.height);

					var greenRect = new createjs.Bitmap(img);
					greenRect.scaleX = scale;
					greenRect.scaleY = scale;

					mc.addChild(greenRect);
					greenRect.x = 0;
					greenRect.y = 0;

					// Resim yüklendikten sonra boyutu güncelle
					updateImageSize(greenRect, maxWidth, maxHeight);
				};
			}

			function updateImageSize(imgObject, maxWidth, maxHeight) {
				// Resmin oranını koruyarak genişlik ve yüksekliği sınırla
				var scale = Math.min(maxWidth / imgObject.image.width, maxHeight / imgObject.image.height);

				imgObject.scaleX = scale;
				imgObject.scaleY = scale;
			}


			//Sıralama yapıp ilk 3 olan açılan listeye yazdırıyoruz.
			function LeaderOrderFnc() {
				LeaderOrderList.splice(0, LeaderOrderList.length); // Önce diziyi komple boşaltıyoruz.
				var j = 0;
				Object.entries(GamerInformation).forEach(p => {

					var _Order = p[1].Order;
					var _Name = p[1].Name;
					var _Gender = p[1].Gender;
					var _Level = p[1].Level;
					var _TaskNo = p[1].TaskNo;
					var TotalPoint = p[1].TotalPoint;
					var BadgeNumber = p[1].BadgeNumber;
					var UpLevel = p[1].UpLevel;//  Burası sonradan eklendi ilk 3 sırlama ada ilerlemesine göre olması için

					//İlk 4 ün bilgilerini dizimize giriyoruz.		
					//LeaderOrderList[0].Order=1;		
					LeaderOrderList.push({
						Order: _Order,
						Level: _Level,
						Name: _Name,
						TaskNo: _TaskNo,
						Gender: _Gender,
						TotalPoint: TotalPoint, // burası sonradan eklendi total point ada içi ilerlemesi getiriliyor 
						BadgeNumber: BadgeNumber
					});
					//ilk üç getirdiğimiz için 4 den küçükleri yazdırıyoruz.	
				});

				// Dizimizi order alanına göre sıralıyoruz.
				LeaderOrderList.sort(function (a, b) {
					return a.Order - b.Order
				});
				//console.log("dizi uzunluk :" + LeaderOrderList.length + " -- " + LeaderOrderList[0].Name + " -- " + LeaderOrderList[1].Name + " -- "+LeaderOrderList[2].Name);
				//4.olanı almadığımız için dizi boyutundan bir çıkartıyoruz.

				for (var i = 0; i < (LeaderOrderList.length); i++) {
					console.log("görev liste:" + LeaderOrderList[i].TotalPoint);
					if (i < 3) {
						var TotalPoint = LeaderOrderList[i].TotalPoint > 30 ? 30 : LeaderOrderList[i].TotalPoint;

						var seviye = LeaderOrderList[i].Level;//Math.floor(Number(LeaderOrderList[i].TotalPoint) / 6) > 4 ? 5 : Math.floor(Number(LeaderOrderList[i].TotalPoint) / 6) + 1;
						var gorev = String(LeaderOrderList[i].TotalPoint);
						var badge = String(LeaderOrderList[i].BadgeNumber);
						console.log("Görev:" + LeaderOrderList[i].TotalPoint);
						_root.LeaderOrder.CampionList["txt_" + (i + 1)].text = LeaderOrderList[i].Name + "\n" + "Seviye " + seviye + " / " + " Görev " + gorev + " /" + " Rozet " + badge;
						_root.FinishedGameMc["Champion_" + String(i + 1)].Name_Txt.text = LeaderOrderList[i].Name;
					}
				};
			}

